@Configuration
@EnableAuthorizationServer
class AuthorizationServerConfig extends AuthorizationServerConfigurerAdapter {
    private final AuthenticationManager authenticationManager;
    private final PasswordEncoder passwordEncoder;

    public AuthorizationServerConfig(AuthenticationManager authenticationManager, PasswordEncoder passwordEncoder) {
        this.authenticationManager = authenticationManager;
        this.passwordEncoder = passwordEncoder;
    }

    @Override
    public void configure(ClientDetailsServiceConfigurer clients) throws Exception {
        clients.inMemory()
                .withClient("client")
                .secret(passwordEncoder.encode("secret"))
                .authorizedGrantTypes("authorization_code", "refresh_token")
                .scopes("read", "write")
                .redirectUris("https://*.example.com/*", "https://example.com/*")
                .accessTokenValiditySeconds(3600)
                .refreshTokenValiditySeconds(2592000);
    }

    @Override
    public void configure(AuthorizationServerEndpointsConfigurer endpoints) throws Exception {
        endpoints
                .authenticationManager(authenticationManager)
                .authorizationCodeServices(authorizationCodeServices())
                .tokenStore(tokenStore());
    }

    @Override
    public void configure(AuthorizationServerSecurityConfigurer security) throws Exception {
        security.checkTokenAccess("isAuthenticated()");
    }

    @Bean
    public AuthorizationCodeServices authorizationCodeServices() {
        return new InMemoryAuthorizationCodeServices() {
            private final Map<String, String> codes = new ConcurrentHashMap<>();
            private final Map<String, Long> expirationTimes = new ConcurrentHashMap<>();
            private final ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(1);

            public AuthorizationCodeServices() {
                scheduler.scheduleAtFixedRate(() -> {
                    long currentTime = System.currentTimeMillis();
                    expirationTimes.entrySet().removeIf(entry -> currentTime > entry.getValue());
                }, 1, 1, TimeUnit.MINUTES);
            }

            @Override
            public String createAuthorizationCode() {
                String code = java.util.UUID.randomUUID().toString();
                codes.put(code, code);
                expirationTimes.put(code, System.currentTimeMillis() + 600000);
                return code;
            }

            @Override
            public void remove(String code) {
                codes.remove(code);
                expirationTimes.remove(code);
            }

            @Override
            public String get(String code) {
                if (expirationTimes.get(code) != null && System.currentTimeMillis() > expirationTimes.get(code)) {
                    codes.remove(code);
                    expirationTimes.remove(code);
                    return null;
                }
                return codes.get(code);
            }
        };
    }

    @Bean
    public TokenStore tokenStore() {
        return new InMemoryTokenStore();
    }
}

@RestController
class AuthorizationController {
    private final ClientDetailsService clientDetailsService;

    public AuthorizationController(ClientDetailsService clientDetailsService) {
        this.clientDetailsService = clientDetailsService;
    }

    @GetMapping("/oauth/authorize")
    public String authorize(
            @RequestParam String response_type,
            @RequestParam String client_id,
            @RequestParam String redirect_uri,
            @RequestParam String scope) throws URISyntaxException {
        ClientDetails client = clientDetailsService.loadClientByClientId(client_id);
        if (!validateRedirectUri(client.getRegisteredRedirectUri(), redirect_uri)) {
            throw new IllegalArgumentException("Invalid redirect_uri");
        }
        return "Authorization successful";
    }

    private boolean validateRedirectUri(Iterable<String> registeredUris, String redirectUri) {
        try {
            URI redirect = new URI(redirectUri);
            for (String registeredUri : registeredUris) {
                URI registered = new URI(registeredUri);
                if (registered.getScheme().equals(redirect.getScheme()) &&
                    registered.getHost().equals(redirect.getHost()) &&
                    registered.getPort() == redirect.getPort()) {
                    if (registered.getPath().equals("/")) {
                        return true;
                    }
                    if (registered.getPath().endsWith("*")) {
                        String basePath = registered.getPath().substring(0, registered.getPath().length() - 1);
                        if (redirect.getPath().startsWith(basePath)) {
                            return true;
                        }
                    } else if (registered.getPath().equals(redirect.getPath())) {
                        return true;
                    }
                }
            }
        } catch (Exception e) {
            return false;
        }
        return false;
    }
}